package tests;import base.BaseTest;import pages.CocineroPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;public class HP02PanelCocineroSeccionesTest extends BaseTest {    @Test    void panelCocineroDistingueSecciones() {        try {            System.out.println(                    "Ejecutando HP-02: Distinción de secciones"            );            LoginPage loginPage = new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion("cocinero", "123");            Thread.sleep(3000);            CocineroPage cocineroPage =                    new CocineroPage(driver);            Assertions.assertTrue(                    cocineroPage.seccionPendientesVisible(),                    "No existe la sección Pedidos Pendientes"            );            Assertions.assertTrue(                    cocineroPage.seccionPreparacionVisible(),                    "No existe la sección Pedidos en Preparación"            );            System.out.println(                    "HP-02 ejecutado correctamente."            );        } catch (Exception e) {            Assertions.fail(e.getMessage());        }    }}